exercises.starter_code:
#include <iostream>

int computeSum(int a, int b)
{
    return a - b;  // BUG: should be addition, not subtraction
}

int computeProduct(int a, int b)
{
    return a + b;  // BUG: should be multiplication, not addition
}

int computeAverage(int a, int b, int c)
{
    return a + b + c / 3;  // BUG: operator precedence -- division happens first
}

int main()
{
    int x{}, y{}, z{};
    std::cin >> x >> y >> z;

    std::cout << "Sum: " << computeSum(x, y) << '\n';
    std::cout << "Product: " << computeProduct(x, y) << '\n';
    std::cout << "Average: " << computeAverage(x, y, z) << '\n';

    return 0;
}

exercises.solution_code:
#include <iostream>

int computeSum(int a, int b)
{
    return a + b;
}

int computeProduct(int a, int b)
{
    return a * b;
}

int computeAverage(int a, int b, int c)
{
    return (a + b + c) / 3;
}

int main()
{
    int x{}, y{}, z{};
    std::cin >> x >> y >> z;

    std::cout << "Sum: " << computeSum(x, y) << '\n';
    std::cout << "Product: " << computeProduct(x, y) << '\n';
    std::cout << "Average: " << computeAverage(x, y, z) << '\n';

    return 0;
}
